      "content": "const { getProjectMembers } = require('../service');
const { sendError } = require('../../lib/errors');

const getProjectMembersById = async (req, res) => {
  try {
    const members = await getProjectMembers(req.params.projectId);
    if (!members) {
      throw sendError(null, 404, 'NOT_FOUND', 'Members not found');
    }
    res.json(members);
  } catch (error) {
    sendError(res, error.status || 500, error.code, error.message);
  }
};

module.exports = { getProjectMembersById };
